// MARK: - Models

struct Stock: Codable, Identifiable, Equatable {
    let id: String
    let symbol: String
    let name: String
    var currentPrice: Double
    var previousClose: Double
    var dayHigh: Double
    var dayLow: Double
    var volume: Int
    var changePercent: Double
    
    var priceChange: Double {
        return currentPrice - previousClose
    }
    
    var isPositive: Bool {
        return priceChange >= 0
    }
}

enum OrderType: String, Codable, CaseIterable {
    case market = "MARKET"
    case limit = "LIMIT"
    case stopLoss = "STOP_LOSS"
    case stopLimit = "STOP_LIMIT"
}

enum OrderSide: String, Codable {
    case buy = "BUY"
    case sell = "SELL"
}

enum OrderStatus: String, Codable {
    case pending = "PENDING"
    case filled = "FILLED"
    case partiallyFilled = "PARTIALLY_FILLED"
    case cancelled = "CANCELLED"
    case rejected = "REJECTED"
    case expired = "EXPIRED"
}

enum TimeInForce: String, Codable, CaseIterable {
    case day = "DAY"
    case gtc = "GTC"
    case ioc = "IOC"
    case fok = "FOK"
}

struct TradeOrder: Codable, Identifiable {
    let id: String
    let symbol: String
    let side: OrderSide
    let type: OrderType
    let quantity: Double
    var limitPrice: Double?
    var stopPrice: Double?
    let timeInForce: TimeInForce
    var status: OrderStatus
    var filledQuantity: Double
    var averageFilledPrice: Double?
    let createdAt: Date
    var updatedAt: Date
    var commission: Double
    
    var totalValue: Double {
        return (averageFilledPrice ?? limitPrice ?? 0) * filledQuantity
    }
}

struct PortfolioPosition: Codable, Identifiable {
    let id: String
    let symbol: String
    let name: String
    var quantity: Double
    var averageCost: Double
    var currentPrice: Double
    
    var marketValue: Double {
        return quantity * currentPrice
    }
    
    var totalCost: Double {
        return quantity * averageCost
    }
    
    var unrealizedPnL: Double {
        return marketValue - totalCost
    }
    
    var unrealizedPnLPercent: Double {
        guard totalCost > 0 else { return 0 }
        return (unrealizedPnL / totalCost) * 100
    }
    
    var isPositive: Bool {
        return unrealizedPnL >= 0
    }
}

struct Portfolio: Codable {
    var positions: [PortfolioPosition]
    var cashBalance: Double
    var buyingPower: Double
    
    var totalMarketValue: Double {
        return positions.reduce(0) { $0 + $1.marketValue }
    }
    
    var totalEquity: Double {
        return totalMarketValue + cashBalance
    }
    
    var totalUnrealizedPnL: Double {
        return positions.reduce(0) { $0 + $1.unrealizedPnL }
    }
    
    var totalUnrealizedPnLPercent: Double {
        let totalCost = positions.reduce(0) { $0 + $1.totalCost }
        guard totalCost > 0 else { return 0 }
        return (totalUnrealizedPnL / totalCost) * 100
    }
}

struct AccountInfo: Codable {
    let accountId: String
    let accountType: String
    var equity: Double
    var cashBalance: Double
    var buyingPower: Double
    var dayTradingBuyingPower: Double
    var maintenanceMargin: Double
    var portfolioValue: Double
}

struct PriceQuote: Codable {
    let symbol: String
    let bid: Double
    let ask: Double
    let last: Double
    let volume: Int
    let timestamp: Date
    
    var spread: Double {
        return ask - bid
    }
}

struct TradeConfirmation: Codable {
