// MARK: - API Error Types

enum TradingError: Error, LocalizedError {
    case insufficientFunds
    case insufficientShares
    case invalidOrder
    case marketClosed
    case networkError(String)
    case authenticationFailed
    case rateLimited
    case serverError(String)
    case invalidSymbol
    case orderRejected(String)
    case encryptionError
    case tokenExpired
    
    var errorDescription: String? {
        switch self {
        case .insufficientFunds: return "Insufficient funds for this trade"
        case .insufficientShares: return "Insufficient shares for this sale"
        case .invalidOrder: return "Invalid order parameters"
        case .marketClosed: return "Market is currently closed"
        case .networkError(let msg): return "Network error: \(msg)"
        case .authenticationFailed: return "Authentication failed"
        case .rateLimited: return "Rate limit exceeded. Please try again later"
        case .serverError(let msg): return "Server error: \(msg)"
        case .invalidSymbol: return "Invalid stock symbol"
        case .orderRejected(let reason): return "Order rejected: \(reason)"
        case .encryptionError: return "Security error occurred"
        case .tokenExpired: return "Session expired. Please log in again"
        }
    }
}

// MARK: - Secure Keychain Manager

final class KeychainManager {
    static let shared = KeychainManager()
    private init() {}
    
    private let serviceName = "com.tradingapp.secure"
    
    func save(key: String, data: Data) -> Bool {
        let query: [String: Any] = [
            kSecClass as String: kSecClassGenericPassword,
            kSecAttrService as String: serviceName,
            kSecAttrAccount as String: key,
            kSecValueData as String: data,
            kSecAttrAccessible as String: kSecAttrAccessibleWhenUnlockedThisDeviceOnly
        ]
        
        SecItemDelete(query as CFDictionary)
        let status = SecItemAdd(query as CFDictionary, nil)
        return status == errSecSuccess
    }
    
    func load(key: String) -> Data? {
        let query: [String: Any] = [
            kSecClass as String: kSecClassGenericPassword,
            kSecAttrService as String: serviceName,
            kSecAttrAccount as String: key,
            kSecReturnData as String: true,
            kSecMatchLimit as String: kSecMatchLimitOne
        ]
        
        var result: AnyObject?
        let status = SecItemCopyMatching(query as CFDictionary, &result)
        
        guard status == errSecSuccess else { return nil }
        return result as? Data
    }
    
    func delete(key: String) -> Bool {
        let query: [String: Any] = [
            kSecClass as String: kSecClassGenericPassword,
            kSecAttrService as String: serviceName,
            kSecAttrAccount as String: key
        ]
        
        let status = SecItemDelete(query as CFDictionary)
        return status == errSecSuccess || status == errSecItemNotFound
    }
    
    func saveString(_ value: String, forKey key: String) -> Bool {
        guard let data = value.data(using: .utf8) else { return false }
        return save(key: key, data: data)
    }
    
    func loadString(forKey key: String) -> String? {
        guard let data = load(key: key) else { return nil }
        return String(data: data, encoding: .utf8)
    }
}

// MARK: - Secure API Communication

final class SecureAPIClient {
    static let shared = SecureAPIClient()
    
    private let baseURL: String
    private let session: URLSession
    private var authToken: String?
    private var refreshToken: String?
    private let requestQueue = DispatchQueue(label: "com.tradingapp.api", qos: .userInitiated)
    private var rateLimitRemaining: Int = 100
    private var rateLimitResetTime: Date?
    
    private init() {
        self.baseURL = "https://api.tradingplatform.com/v1"
        
        let config = URLSessionConfiguration.default
        config.timeoutIntervalForRequest = 15
        config.timeoutIntervalForResource = 30
        config.waitsForConnectivity = true
        config.tlsMinimumSupportedProtocolVersion = .TLSv12
        config.httpAdditionalHeaders = [
            "Content-Type": "application/json",
            "Accept": "application/json",
            "X-Platform": "iOS",
            "X-App-Version": Bundle.main.infoDictionary?["CFBundleShortVersionString"] as? String ?? "1.0"
        ]
        
        self.session = URLSession(configuration: config)
        
        self.authToken = KeychainManager.shared.loadString(forKey: "auth_token")
        self.refreshToken = KeychainManager.shared.loadString(forKey: "refresh_token")
    }
    
    private func generateHMAC(for message: String, using key: String) -> String {
        let keyData = SymmetricKey(data: Data(key.utf8))
        let signature = HMAC<SHA256>.authenticationCode(for: Data(message.utf8), using: keyData)
        return Data(signature).base64EncodedString()
    }
    
    private func generateNonce() -> String {
        var bytes = [UInt8](repeating: 0, count: 32)
        _ = SecRandomCopyBytes(kSecRandomDefault, bytes.count, &bytes)
        return Data(bytes).base64EncodedString()
    }
    
    func authenticate(username: String, password: String) async throws -> Bool {
        let hashedPassword = SHA256.hash(data: Data(password.utf8))
            .compactMap { String(format: "%02x", $0) }
            .joined()
        
        let body: [String: Any] = [
            "username": username,
            "password": hashedPassword,
            "nonce": generateNonce(),
            "timestamp": ISO8601DateFormatter().string(from: Date())
        ]
        
        let response: AuthResponse = try await performRequest(
            endpoint: "/auth/login",
            method: "POST",
            body: body,
            requiresAuth: false
        )
        
        self.authToken = response.accessToken
        self.refreshToken = response.refreshToken
        
        _ = KeychainManager.shared.saveString(response.accessToken, forKey: "auth_token")
        _ = KeychainManager.shared.saveString(response.refreshToken, forKey: "refresh_token")
        
        return true
    }
    
    func refreshAuthToken() async throws {
        guard let refreshToken = refreshToken else {
            throw TradingError.tokenExpired
        }
        
        let body: [String: Any] = [
            "refresh_token": refreshToken,
            "timestamp": ISO8601DateFormatter().string(from: Date())
        ]
        
        let response: AuthResponse = try await performRequest(
            endpoint: "/auth/refresh",
            method: "POST",
            body: body,
            requiresAuth: false
        )
        
        self.authToken = response.accessToken
        self.refreshToken = response.refreshToken
        
        _ = KeychainManager.shared.saveString(response.accessToken, forKey: "auth_token")
        _ = KeychainManager.shared.saveString(response.refreshToken, forKey: "refresh_token")
    }
    
    func performRequest<T: Decodable>(
        endpoint: String,
        method: String = "GET",
        body: [String: Any]? = nil,
        queryParams: [String: String]? = nil,
        requiresAuth: Bool = true
    ) async throws -> T {
        if let resetTime = rateLimitResetTime, rateLimitRemaining <= 0 {
            if Date() < resetTime {
                throw TradingError.rateLimited
            }
        }
        
        var urlString = baseURL + endpoint
        
        if let queryParams = queryParams {
            var components = URLComponents(string: urlString)!
            components.queryItems = queryParams.map { URLQueryItem(name: $0.key, value: $0.value) }
            urlString = components.url!.absoluteString
        }
        
        guard let url = URL(string: urlString) else {
            throw TradingError.networkError("Invalid URL")
        }
        
        var request = URLRequest(url: url)
        request.httpMethod = method
        
        if requiresAuth {
            guard let token = authToken else {
                throw TradingError.authenticationFailed
            }
            request.setValue("Bearer \(token)", forHTTPHeaderField: "Authorization")
            
            let timestamp = String(Int(Date().timeIntervalSince1970))
            let nonce = generateNonce()
            let message = "\(method)\(endpoint)\(timestamp)\(nonce)"
            let signature = generateHMAC(for: message, using: token)
            
            request.setValue(timestamp, forHTTPHeaderField: "X-Timestamp")
            request.setValue(nonce, forHTTPHeaderField: "X-Nonce")
            request.setValue(signature, forHTTPHeaderField: "X-Signature")
        }
        
        if let body = body {
            request.httpBody = try JSONSerialization.data(withJSONObject: body)
        }
        
        let (data, response) = try await session.data(for: request)
        
        guard let httpResponse = response as? HTTPURLResponse else {
            throw TradingError.networkError("Invalid response")
        }
        
        if let remaining = httpResponse.value(forHTTPHeaderField: "X-RateLimit-Remaining") {
            rateLimitRemaining = Int(remaining) ?? 100
        }
        if let resetTime = httpResponse.value(forHTTPHeaderField: "X-RateLimit-Reset") {
            rateLimitResetTime = Date(timeIntervalSince1970: Double(resetTime) ?? 0)
        }
        
        switch httpResponse.statusCode {
        case 200...299:
            let decoder = JSONDecoder()
            decoder.dateDecodingStrategy = .iso8601
            return try decoder.decode(T.self, from: data)
        case 401:
            if requiresAuth {
                try await refreshAuthToken()
                return try await performRequest(
                    endpoint: endpoint,
                    method: method,
                    body: body,
                    queryParams: queryParams,
                    requiresAuth: requiresAuth
                )
            }
            throw TradingError.authenticationFailed
        case 429:
            throw TradingError.rateLimited
        default:
            if let errorResponse = try? JSONDecoder().decode(APIErrorResponse.self, from: data) {
                throw TradingError.serverError(errorResponse.message)
            }
            throw TradingError.serverError("Status code: \(httpResponse.statusCode)")
        }
    }
    
    func logout() {
        authToken = nil
        refreshToken = nil
        _ = KeychainManager.shared.delete(key: "auth_token")
        _ = KeychainManager.shared.delete(key: "refresh_token")
    }
}

struct AuthResponse: Codable {
    let accessToken: String
    let refreshToken: String
    let expiresIn: Int
}

struct APIErrorResponse: Codable {
    let code: String
    let message: String
}

// MARK: - WebSocket Manager for Real-Time Data

final class WebSocketManager: NSObject, URLSessionWebSocketDelegate {
    static let shared = WebSocketManager()
    
    private var webSocket: URLSessionWebSocketTask?
    private var session: URLSession!
    private var subscribedSymbols: Set<String> = []
    private var reconnectAttempts = 0
    private let maxReconnectAttempts = 5
    private var isConnected = false
    private var pingTimer: Timer?
    
    var onPriceUpdate: ((String, PriceQuote) -> Void)?
    var onOrderUpdate: ((TradeOrder) -> Void)?
    var onConnectionStatusChanged: ((Bool) -> Void)?
    
    private override init() {
        super.init()
        session = URLSession(configuration: .default, delegate: self, delegateQueue: OperationQueue())
    }
    
    func connect() {
        guard let url = URL(string: "wss://ws.tradingplatform.com/v1/stream") else { return }
        
        var request = URLRequest(url: url)
        if let token = KeychainManager.shared.loadString(forKey: "auth_token") {
            request.setValue("Bearer \(token)", forHTTPHeaderField: "Authorization")
        }
        
        webSocket = session.webSocketTask(with: request)
        webSocket?.resume()
        
        startReceiving()
        startPingTimer()
    }
    
    func disconnect() {
        pingTimer?.invalidate()
        pingTimer = nil
        webSocket?.cancel(with: .goingAway, reason: nil)
        isConnected = false
        onConnectionStatusChanged?(false)
    }
    
    func subscribe(to symbols: [String]) {
        subscribedSymbols.formUnion(symbols)
        
        let message: [String: Any] = [
            "action": "subscribe",
            "channels": ["quotes", "trades"],
            "symbols": symbols
        ]
        
        sendJSON(message)
    }
    
    func unsubscribe(from symbols: [String]) {
        subscribedSymbols.subtract(symbols)
        
        let message: [String: Any] = [
            "action": "unsubscribe",
            "symbols": symbols
        ]
        
        sendJSON(message)
    }
    
    private func sendJSON(_ dict: [String: Any]) {
        guard let data = try? JSONSerialization.data(withJSONObject: dict),
              let string = String(data: data, encoding: .utf8) else { return }
        
        webSocket?.send(.string(string)) { error in
            if let error = error {
                print("WebSocket send error: \(error)")
            }
        }
    }
    
    private func startReceiving() {
        webSocket?.receive { [weak self] result in
            switch result {
            case .success(let message):
                switch message {
                case .string(let text):
                    self?.handleMessage(text)
                case .data(let data):
                    if let text = String(data: data, encoding: .utf8) {
                        self?.handleMessage(text)
                    }
                @unknown default:
                    break
                }
                self?.startReceiving()
                
            case .failure(let error):
                print("WebSocket receive error: \(error)")
                self?.handleDisconnection()
            }
        }
    }
    
    private func handleMessage(_ text: String) {
        guard let data = text.data(using: .utf8),
              let json = try? JSONSerialization.jsonObject(with: data) as? [String: Any],
              let type = json["type"] as? String else { return }
        
        let decoder = JSONDecoder()
        decoder.dateDecodingStrategy = .iso8601
        
        switch type {
        case "quote":
            if let quoteData = try? JSONSerialization.data(withJSONObject: json["data"] as Any),
               let quote = try? decoder.decode(PriceQuote.self, from: quoteData) {
                DispatchQueue.main.async {
                    self.onPriceUpdate?(quote.symbol, quote)
                }
            }
        case "order_update":
            if let orderData = try? JSONSerialization.data(withJSONObject: json["data"] as Any),
               let order = try? decoder.decode(TradeOrder.self, from: orderData) {
                DispatchQueue.main.async {
                    self.onOrderUpdate?(order)
                }
            }
        default:
            break
        }
    }
    
    private func startPingTimer() {
        pingTimer?.invalidate()
        pingTimer = Timer.scheduledTimer(withTimeInterval: 30, repeats: true) { [weak self] _ in
            self?.webSocket?.sendPing { error in
                if let error = error {
                    print("Ping error: \(error)")
                    self?.handleDisconnection()
                }
            }
        }
    }
    
    private func handleDisconnection() {
        isConnected = false
        DispatchQueue.main.async {
            self.onConnectionStatusChanged?(false)
        }
        
        guard reconnectAttempts < maxReconnectAttempts else {
            print("Max reconnection attempts reached")
            return
        }
        
        reconnectAttempts += 1
        let delay = Double(reconnectAttempts) * 2.0
        
        DispatchQueue.main.asyncAfter(deadline: .now() + delay) { [weak self] in
            self?.connect()
            if let symbols = self?.subscribedSymbols, !symbols.isEmpty {
                self?.subscribe(to: Array(symbols))
            }
        }
    }
    
    // MARK: URLSessionWebSocketDelegate
    
    func urlSession(_ session: URLSession, webSocketTask: URLSessionWebSocketTask, didOpenWithProtocol protocol: String?) {
        isConnected = true
        reconnectAttempts = 0
        DispatchQueue.main.async {
            self.onConnectionStatusChanged?(true)
        }
    }
    
    func urlSession(_ session: URLSession, webSocketTask: URLSessionWebSocketTask, didCloseWith closeCode: URLSessionWebSocketTask.CloseCode, reason: Data?) {
        handleDisconnection()
    }
}

// MARK: - Trading Service

final class TradingService {
    static let shared = TradingService()
    private let api = SecureAPIClient.shared
    
    private init() {}
    
    func getQuote(symbol: String) async throws -> PriceQuote {
        return try await api.performRequest(
            endpoint: "/quotes/\(symbol)"
        )
    }
    
    func getQuotes(symbols: [String]) async throws -> [PriceQuote] {
        return try await api.performRequest(
            endpoint: "/quotes",
            queryParams: ["symbols": symbols.joined(separator: ",")]
        )
    }
    
    func placeOrder(
        symbol: String,
        side: OrderSide,
        type: OrderType,
        quantity: Double,
        limitPrice: Double? = nil,
        stopPrice: Double? = nil,
        timeInForce: TimeInForce = .day
    ) async throws -> TradeOrder {
        guard quantity > 0 else {
            throw TradingError.invalidOrder
        }
        
        if type == .limit || type == .stopLimit {
            guard limitPrice != nil && limitPrice! > 0 else {
                throw TradingError.invalidOrder
            }
        }
        
        if type == .stopLoss || type == .stopLimit {
            guard stopPrice != nil && stopPrice! > 0 else {
                throw TradingError.invalidOrder
            }
        }
        
        var body: [String: Any] = [
            "symbol": symbol,
            "side": side.rawValue,
            "type": type.rawValue,
            "quantity": quantity,
            "time_in_force": timeInForce.rawValue
        ]
        
        if let limitPrice = limitPrice {
            body["limit_price"] = limitPrice
        }
        if let stopPrice = stopPrice {
            body["stop_price"] = stopPrice
        }
        
        return try await api.performRequest(
            endpoint: "/orders",
            method: "POST",
            body: body
        )
    }
    
    func cancelOrder(orderId: String) async throws -> TradeOrder {
        return try await api.performRequest(
            endpoint: "/orders/\(orderId)",
            method: "DELETE"
        )
    }
    
    func getOrder(orderId: String) async throws -> TradeOrder {
        return try await api.performRequest(
            endpoint: "/orders/\(orderId)"
        )
    }
    
    func getOpenOrders() async throws -> [TradeOrder] {
        return try await api.performRequest(
            endpoint: "/orders",
            queryParams: ["status": "open"]
        )
    }
    
    func getOrderHistory(limit: Int = 50) async throws -> [TradeOrder] {
        return try await api.performRequest(
            endpoint: "/orders/history",
            queryParams: ["limit": String(limit)]
        )
    }
    
    func getPortfolio() async throws -> Portfolio {
        return try await api.performRequest(
            endpoint: "/portfolio"
        )
    }
    
    func getAccountInfo() async throws -> AccountInfo {
        return try await api.performRequest(
            endpoint: "/account"
        )
    }
    
    func searchStocks(query: String) async throws -> [Stock] {
        return try await api.performRequest(
            endpoint: "/stocks/search",
            queryParams: ["q": query]
        )
    }
    
    func getEstimatedCost(
        symbol: String,
        side: OrderSide,
        type: OrderType,
        quantity: Double,
        limitPrice: Double? = nil
    ) async throws -> OrderEstimate {
        var body: [String: Any] = [
            "symbol": symbol,
            "side": side.rawValue,
            "type": type.rawValue,
            "quantity": quantity
        ]
        if let limitPrice = limitPrice {
            body["limit_price"] = limitPrice
        }
        
        return try await api.performRequest(
            endpoint: "/orders/estimate",
            method: "POST",
            body: body
        )
    }
}

struct OrderEstimate: Codable {
    let estimatedPrice: Double
    let estimatedTotal: Double
    let estimatedCommission: Double
    let estimatedGrandTotal: Double
}

// MARK: - Portfolio Manager

final class PortfolioManager: ObservableObject {
    static let shared = PortfolioManager()
    
    @Published var portfolio: Portfolio?
    @Published var accountInfo: AccountInfo?
    @Published var openOrders: [TradeOrder] = []
    @Published var orderHistory: [TradeOrder] = []
    @Published var isLoading = false
    @Published var error: TradingError?
    @Published var isConnected = false
    
    private let tradingService = TradingService.shared
    private let webSocket = WebSocketManager.shared
    private var cancellables = Set<AnyCancellable>()
    private var refreshTimer: Timer?
    
    private init() {
        setupWebSocket()
    }
    
    private func setupWebSocket() {
        webSocket.onPriceUpdate = { [weak self] symbol, quote in
            self?.updatePositionPrice(symbol: symbol, price: quote.last)
        }
        
        webSocket.onOrderUpdate = { [weak self] order in
            self?.handleOrderUpdate(order)
        }
        
        webSocket.onConnectionStatusChanged = { [weak self] connected in
            self?.isConnected = connected
        }
    }
    
    func startRealTimeUpdates() {
        webSocket.connect()
        
        if let symbols = portfolio?.positions.map({ $0.symbol }), !symbols.isEmpty {
            webSocket.subscribe(to: symbols)
        }
        
        refreshTimer = Timer.scheduledTimer(withTimeInterval: 60, repeats: true) { [weak self] _ in
            Task {
                await self?.refreshPortfolio()
            }
        }
    }
    
    func stopRealTimeUpdates() {
        webSocket.disconnect()
        refreshTimer?.invalidate()
        refreshTimer = nil
    }
    
    @MainActor
    func refreshAll() async {
        isLoading = true
        error = nil
        
        do {
            async let portfolioTask = tradingService.getPortfolio()
            async let accountTask = tradingService.getAccountInfo()
            async let ordersTask = tradingService.getOpenOrders()
            async let historyTask = tradingService.getOrderHistory()
            
            let (p, a, o, h) = try await (portfolioTask, accountTask, ordersTask, historyTask)
            
            self.portfolio = p
            self.accountInfo = a
            self.openOrders = o
            self.orderHistory = h
            
            let symbols = p.positions.map { $0.symbol }
            if !symbols.isEmpty {
                webSocket.subscribe(to: symbols)
            }
        } catch let err as TradingError {
            self.error = err
        } catch {
            self.error = .networkError(error.localizedDescription)
        }
        
        isLoading = false
    }
    
    @MainActor
    func refreshPortfolio() async {
        do {
            portfolio = try await tradingService.getPortfolio()
        } catch {
            print("Portfolio refresh error: \(error)")
        }
    }
    
    private func updatePositionPrice(symbol: String, price: Double) {
        guard var portfolio = portfolio else { return }
        if let index = portfolio.positions.firstIndex(where: { $0.symbol == symbol }) {
            portfolio.positions[index].currentPrice = price
            self.portfolio = portfolio
        }
    }
    
    private func handleOrderUpdate(_ order: TradeOrder) {
        if let index = openOrders.firstIndex(where: { $0.id == order.id }) {
            if order.status == .filled || order.status == .cancelled || order.status == .rejected || order.status == .expired {
                openOrders.remove(at: index)
                orderHistory.insert(order, at: 0)
            } else {
                openOrders[index] = order
            }
        }
        
        if order.status == .filled {
            Task {
                await refreshPortfolio()
            }
        }
    }
    
    @MainActor
    func executeTrade(
        symbol: String,
        side: OrderSide,
        type: OrderType,
        quantity: Double,
        limitPrice: Double? = nil,
        stopPrice: Double? = nil,
        timeInForce: TimeInForce = .day
    ) async throws -> TradeOrder {
        if side == .buy {
            guard let buyingPower = portfolio?.buyingPower else {
                throw TradingError.insufficientFunds
            }
            let estimatedCost = (limitPrice ?? 0) * quantity
            if type == .market {
                // Market orders use estimated price check on server
            } else if estimatedCost > buyingPower {
                throw TradingError.insufficientFunds
            }
        }
        
        if side == .sell {
            if let position = portfolio?.positions.first(where: { $0.symbol == symbol }) {
                if quantity > position.quantity {
                    throw TradingError.insufficientShares
                }
            } else {
                throw TradingError.insufficientShares
            }
        }
        
        let order = try await tradingService.placeOrder(
            symbol: symbol,
            side: side,
            type: type,
            quantity: quantity,
            limitPrice: limitPrice,
            stopPrice: stopPrice,
            timeInForce: timeInForce
        )
        
        if order.status != .filled && order.status != .cancelled && order.status != .rejected {
            openOrders.insert(order, at: 0)
        } else {
            orderHistory.insert(order, at: 0)
        }
        
        if order.status == .filled {
            await refreshPortfolio()
        }
        
        return order
    }
    
    @MainActor
    func cancelOrder(_ orderId: String) async throws {
        let cancelledOrder = try await tradingService.cancelOrder(orderId: orderId)
        if let index = openOrders.firstIndex(where: { $0.id == orderId }) {
            openOrders.remove(at: index)
        }
        orderHistory.insert(cancelledOrder, at: 0)
    }
}

