@MainActor
final class TradeViewModel: ObservableObject {
    @Published var symbol: String = ""
    @Published var selectedSide: OrderSide = .buy
    @Published var selectedOrderType: OrderType = .market
    @Published var quantity: String = ""
    @Published var limitPrice: String = ""
    @Published var stopPrice: String = ""
    @Published var selectedTimeInForce: TimeInForce = .day
    @Published var currentQuote: PriceQuote?
    @Published var orderEstimate: OrderEstimate?
    @Published var isSubmitting = false
    @Published var showConfirmation = false
    @Published var lastOrder: TradeOrder?
    @Published var errorMessage: String?
    @Published var searchResults: [Stock] = []
    @Published var isSearching = false
    
    private let tradingService = TradingService.shared
    private let portfolioManager = PortfolioManager.shared
    private var cancellables = Set<AnyCancellable>()
    private var quoteRefreshTimer: Timer?
    
    init() {
        setupSearch()
    }
    
    private func setupSearch() {
        $symbol
            .debounce(for: .milliseconds(300), scheduler: RunLoop.main)
            .removeDuplicates()
            .sink { [weak self] query in
                guard let self = self, query.count >= 1 else {
                    self?.searchResults = []
                    return
                }
                Task {
                    await self.searchStocks(query: query)
                }
            }
            .store(in: &cancellables)
    }
    
    func searchStocks(query: String) async {
        isSearching = true
        do {
            searchResults = try await tradingService.searchStocks(query: query)
        } catch {
            searchResults = []
        }
        isSearching = false
    }
    
    func selectStock(_ stock: Stock) {
        symbol = stock.symbol
        searchResults = []
        Task {
            await refreshQuote()
        }
    }
    
    func refreshQuote() async {
        guard !symbol.isEmpty else { return }
        do {
            currentQuote = try await tradingService.getQuote(symbol: symbol)
        } catch {
            errorMessage = "Failed to get quote: \(error.localizedDescription)"
        }
    }
    
    func startQuoteRefresh() {
        quoteRefreshTimer = Timer.scheduledTimer(withTimeInterval: 5, repeats: true) { [weak self] _ in
            Task { [weak self] in
                await self?.refreshQuote()
            }
        }
    }
    
    func stopQuoteRefresh() {
        quoteRefreshTimer?.invalidate()
        quoteRefreshTimer = nil
    }
    
    func getEstimate() async {
        guard let qty = Double(quantity), qty > 0 else { return }
        
        do {
            orderEstimate = try await tradingService.getEstimatedCost(
                symbol: symbol,
                side: selectedSide,
                type: selectedOrderType,
                quantity: qty,
                limitPrice: Double(limitPrice)
            )
        } catch {
            print("Estimate error: \(error)")
        }
    }
    
    func submitOrder() async {
        guard !symbol.isEmpty else {
            errorMessage = "Please enter a symbol"
            return
        }
        
        guard let qty = Double(quantity), qty > 0 else {
            errorMessage = "Please enter a valid quantity"
            return
        }
        
        var limitPriceValue: Double?
        var stopPriceValue: Double?
        
        if selectedOrderType == .limit || selectedOrderType == .stopLimit {
            guard let price = Double(limitPrice), price > 0 else {
                errorMessage = "Please enter a valid limit price"
                return
            }
            limitPriceValue = price
        }
        
        if selectedOrderType == .stopLoss || selectedOrderType == .stopLimit {
            guard let price = Double(stopPrice), price > 0 else {
                errorMessage = "Please enter a valid stop price"
                return
            }
            stopPriceValue = price
        }
        
        isSubmitting = true
        errorMessage = nil
        
        do {
            lastOrder = try await portfolioManager.executeTrade(
                symbol: symbol.uppercased(),
                side: selectedSide,
                type: selectedOrderType,
                quantity: qty,
                limitPrice: limitPriceValue,
                stopPrice: stopPriceValue,
                timeInForce: selectedTimeInForce
            )
            showConfirmation = true
        } catch let error as TradingError {
            errorMessage = error.localizedDescription
        } catch {
            errorMessage = error.localizedDescription
        }
        
        isSubmitting = false
    }
    
    func resetForm() {
        quantity = ""
        limitPrice = ""
        stopPrice = ""
        selectedOrderType = .market
        selectedTimeInForce = .day
        orderEstimate = nil
        errorMessage = nil
    }
}

@MainActor
final class PortfolioViewModel: ObservableObject {
    @Published var portfolio: Portfolio?
    @Published var accountInfo: AccountInfo?
    @Published var openOrders: [TradeOrder] = []
    @Published var orderHistory: [TradeOrder] = []
    @Published var isLoading = false
    @Published var errorMessage: String?
    @Published var selectedTab: PortfolioTab = .positions
    @Published var sortOrder: SortOrder = .value
    
    enum PortfolioTab: String, CaseIterable {
        case positions = "Positions"
        case orders = "Open Orders"
        case history = "History"
    }
    
    enum SortOrder: String, CaseIterable {
        case value = "Value"
        case pnl = "P&L"
        case name = "Name"
        case change = "% Change"
    }
    
    private let portfolioManager = PortfolioManager.shared
    private var cancellables = Set<AnyCancellable>()
    
    init() {
        portfolioManager.$portfolio
            .receive(on: DispatchQueue.main)
            .assign(to: &$portfolio)
        
        portfolioManager.$accountInfo
            .receive(on: DispatchQueue.main)
            .assign(to: &$accountInfo)
        
        portfolioManager.$openOrders
            .receive(on: DispatchQueue.main)
            .assign(to: &$openOrders)
        
        portfolioManager.$orderHistory
            .receive(on: DispatchQueue.main)
            .assign(to: &$orderHistory)
        
        portfolioManager.$isLoading
            .receive(on: DispatchQueue.main)
            .assign(to: &$isLoading)
        
        portfolioManager.$error
            .receive(on: DispatchQueue.main)
            .map { $0?.localizedDescription }
            .assign(to: &$errorMessage)
    }
    
    var sortedPositions: [PortfolioPosition] {
        guard let positions = portfolio?.positions else { return [] }
        
        switch sortOrder {
        case .value:
            return positions.sorted { $0.marketValue > $1.marketValue }
        case .pnl:
            return positions.sorted { $0.unrealizedPnL > $1.unrealizedPnL }
        case .name:
            return positions.sorted { $0.symbol < $1.symbol }
        case .change:
            return positions.sorted { $0.unrealizedPnLPercent > $1.unrealizedPnLPercent }
        }
    }
    
    func refresh() async {
        await portfolioManager.refreshAll()
    }
    
    func cancelOrder(_ orderId: String) async {
        do {
            try await portfolioManager.cancelOrder(orderId)
        } catch {
            errorMessage = "Failed to cancel order: \(error.localizedDescription)"
        }
    }
}

