final class PortfolioViewController: UIViewController {
    
    private let viewModel = PortfolioViewModel()
    private var cancellables = Set<AnyCancellable>()
    
    private lazy var scrollView: UIScrollView = {
        let sv = UIScrollView()
        sv.translatesAutoresizingMaskIntoConstraints = false
        sv.alwaysBounceVertical = true
        sv.refreshControl = refreshControl
        return sv
    }()
    
    private lazy var contentStack: UIStackView = {
        let stack = UIStackView()
        stack.translatesAutoresizingMaskIntoConstraints = false
        stack.axis = .vertical
        stack.spacing = 16
        stack.layoutMargins = UIEdgeInsets(top: 16, left: 16, bottom: 16, right: 16)
        stack.isLayoutMarginsRelativeArrangement = true
        return stack
    }()
    
    private lazy var refreshControl: UIRefreshControl = {
        let rc = UIRefreshControl()
        rc.addTarget(self, action: #selector(handleRefresh), for: .valueChanged)
        return rc
    }()
    
    private let equityLabel = UILabel()
    private let equityValueLabel = UILabel()
    private let pnlLabel = UILabel()
    private let cashLabel = UILabel()
    private let buyingPowerLabel = UILabel()
    private let positionsTableView = UITableView()
    private let loadingIndicator = UIActivityIndicatorView(style: .large)
    private var positionsHeightConstraint: NSLayoutConstraint?
    
    override func viewDidLoad() {
        super.viewDidLoad()
        title = "Portfolio"
        view.backgroundColor = .systemBackground
        
        setupUI()
        bindViewModel()
        
        Task {
            await viewModel.refresh()
        }
    }
    
    private func setupUI() {
        view.addSubview(scrollView)
        scrollView.addSubview(contentStack)
        
        NSLayoutConstraint.activate([
            scrollView.topAnchor.constraint(equalTo: view.safeAreaLayoutGuide.topAnchor),
            scrollView.leadingAnchor.constraint(equalTo: view.leadingAnchor),
            scrollView.trailingAnchor.constraint(equalTo: view.trailingAnchor),
            scrollView.bottomAnchor.constraint(equalTo: view.bottomAnchor),
            
            contentStack.topAnchor.constraint(equalTo: scrollView.contentLayoutGuide.topAnchor),
            contentStack.leadingAnchor.constraint(equalTo: scrollView.contentLayoutGuide.leadingAnchor),
            contentStack.trailingAnchor.constraint(equalTo: scrollView.contentLayoutGuide.trailingAnchor),
            contentStack.bottomAnchor.constraint(equalTo: scrollView.contentLayoutGuide.bottomAnchor),
            contentStack.widthAnchor.constraint(equalTo: scrollView.frameLayoutGuide.widthAnchor)
        ])
        
        // Account Summary Card
        let summaryCard = createSummaryCard()
        contentStack.addArrangedSubview(summaryCard)
        
        // Positions Section
        let positionsHeader = createSectionHeader(title: "Positions")
        contentStack.addArrangedSubview(positionsHeader)
        
        positionsTableView.translatesAutoresizingMaskIntoConstraints = false
        positionsTableView.delegate = self
        positionsTableView.dataSource = self
        positionsTableView.register(PositionCell.self, forCellReuseIdentifier: PositionCell.identifier)
        positionsTableView.isScrollEnabled = false
        positionsTableView.separatorStyle = .singleLine
        positionsTableView.rowHeight = 72
        contentStack.addArrangedSubview(positionsTableView)
        
        positionsHeightConstraint = positionsTableView.heightAnchor.constraint(equalToConstant: 200)
        positionsHeightConstraint?.isActive = true
        
        // Loading Indicator
        loadingIndicator.translatesAutoresizingMaskIntoConstraints = false
        view.addSubview(loadingIndicator)
        loadingIndicator.centerXAnchor.constraint(equalTo: view.centerXAnchor).isActive = true
        loadingIndicator.centerYAnchor.constraint(equalTo: view.centerYAnchor).isActive = true
    }
    
    private func createSummaryCard() -> UIView {
        let card = UIView()
        card.backgroundColor = .secondarySystemBackground
        card.layer.cornerRadius = 12
        card.translatesAutoresizingMaskIntoConstraints = false
        
        let stack = UIStackView()
        stack.axis = .vertical
        stack.spacing = 8
        stack.translatesAutoresizingMaskIntoConstraints = false
        
        equityLabel.text = "Total Equity"
        equityLabel.font = .systemFont(ofSize: 14, weight: .medium)
        equityLabel.textColor = .secondaryLabel
        
        equityValueLabel.text = "$0.00"
        equityValueLabel.font = .systemFont(ofSize: 32, weight: .bold)
        
        pnlLabel.text = "+$0.00 (0.00%)"
        pnlLabel.font = .systemFont(ofSize: 16, weight: .medium)
        pnlLabel.textColor = .systemGreen
        
        let divider = UIView()
        divider.backgroundColor = .separator
        divider.heightAnchor.constraint(equalToConstant: 1).isActive = true
        
        let detailsStack = UIStackView()
        detailsStack.axis = .horizontal
        detailsStack.distribution = .fillEqually
        
        let cashStack = createDetailItem(title: "Cash", valueLabel: cashLabel)
        let bpStack = createDetailItem(title: "Buying Power", valueLabel: buyingPowerLabel)
        
        detailsStack.addArrangedSubview(cashStack)
        detailsStack.addArrangedSubview(bpStack)
        
        stack.addArrangedSubview(equityLabel)
        stack.addArrangedSubview(equityValueLabel)
        stack.addArrangedSubview(pnlLabel)
        stack.addArrangedSubview(divider)
        stack.addArrangedSubview(detailsStack)
        
        card.addSubview(stack)
        NSLayoutConstraint.activate([
            stack.topAnchor.constraint(equalTo: card.topAnchor, constant: 16),
            stack.leadingAnchor.constraint(equalTo: card.leadingAnchor, constant: 16),
            stack.trailingAnchor.constraint(equalTo: card.trailingAnchor, constant: -16),
            stack.bottomAnchor.constraint(equalTo: card.bottomAnchor, constant: -16)
        ])
        
        return card
    }
    
    private func createDetailItem(title: String, valueLabel: UILabel) -> UIStackView {
        let stack = UIStackView()
        stack.axis = .vertical
        stack.spacing = 4
        
        let titleLabel = UILabel()
        titleLabel.text = title
        titleLabel.font = .systemFont(ofSize: 12, weight: .medium)
        titleLabel.textColor = .secondaryLabel
        
        valueLabel.text = "$0.00"
        valueLabel.font = .systemFont(ofSize: 18, weight: .semibold)
        
        stack.addArrangedSubview(titleLabel)
        stack.addArrangedSubview(valueLabel)
        
        return stack
    }
    
    private func createSectionHeader(title: String) -> UIView {
        let container = UIView()
        let label = UILabel()
        label.text = title
        label.font = .systemFont(ofSize: 20, weight: .bold)
        label.translatesAutoresizingMaskIntoConstraints = false
        container.addSubview(label)
        
        NSLayoutConstraint.activate([
            label.topAnchor.constraint(equalTo: container.topAnchor),
            label.leadingAnchor.constraint(equalTo: container.leadingAnchor),
            label.trailingAnchor.constraint(equalTo: container.trailingAnchor),
            label.bottomAnchor.constraint(equalTo: container.bottomAnchor)
        ])
        
        return container
    }
    
    private func bindViewModel() {
        viewModel.$portfolio
            .receive(on: DispatchQueue.main)
            .sink { [weak self] portfolio in
                self?.updateSummary(portfolio: portfolio)
                self?.positionsTableView.reloadData()
                self?.updateTableHeight()
            }
            .store(in: &cancellables)
        
        viewModel.$isLoading
            .receive(on: DispatchQueue.main)
            .sink { [weak self] loading in
                if loading {
                    self?.loadingIndicator.startAnimating()
                } else {
                    self?.loadingIndicator.stopAnimating()
                    self?.refreshControl.endRefreshing()
                }
            }
            .store(in: &cancellables)
    }
    
    private func updateSummary(portfolio: Portfolio?) {
        guard let portfolio = portfolio else { return }
        
        let formatter = NumberFormatter()
        formatter.numberStyle = .currency
        formatter.locale = Locale(identifier: "en_US")
        
        equityValueLabel.text = formatter.string(from: NSNumber(value: portfolio.totalEquity))
        
        let pnlValue = portfolio.totalUnrealizedPnL
        let pnlPercent = portfolio.totalUnrealizedPnLPercent
        let pnlSign = pnlValue >= 0 ? "+" : ""
        pnlLabel.text = "\(pnlSign)\(formatter.string(from: NSNumber(value: pnlValue)) ?? "$0.00") (\(String(format: "%.2f", pnlPercent))%)"
        pnlLabel.textColor = pnlValue >= 0 ? .systemGreen : .systemRed
        
        cashLabel.text = formatter.string(from: NSNumber(value: portfolio.cashBalance))
        buyingPowerLabel.text = formatter.string(from: NSNumber(value: portfolio.buyingPower))
    }
    
    private func updateTableHeight() {
        let count = viewModel.sortedPositions.count
        positionsHeightConstraint?.constant = CGFloat(max(count, 1)) * 72
    }
    
    @objc private func handleRefresh() {
        Task {
            await viewModel.refresh()
        }
    }
}

extension PortfolioViewController: UITableViewDelegate, UITableViewDataSource {
    func tableView(_ tableView: UITableView, numberOfRowsInSection section: Int) -> Int {
        return viewModel.sortedPositions.count
    }
    
    func tableView(_ tableView: UITableView, cellForRowAt indexPath: IndexPath) -> UITableViewCell {
        guard let cell = tableView.dequeueReusableCell(withIdentifier: PositionCell.identifier, for: indexPath) as? PositionCell else {
            return UITableViewCell()
        }
        let position = viewModel.sortedPositions[indexPath.row]
        cell.configure(with: position)
        return cell
    }
    
    func tableView(_ tableView: UITableView, didSelectRowAt indexPath: IndexPath) {
        tableView.deselectRow(at: indexPath, animated: true)
        let position = viewModel.sortedPositions[indexPath.row]
        let detailVC = StockDetailViewController(symbol: position.symbol)
        navigationController?.pushViewController(detailVC, animated: true)
    }
    
    func tableView(_ tableView: UITableView, trailingSwipeActionsConfigurationForRowAt indexPath: IndexPath) -> UISwipeActionsConfiguration? {
        let position = viewModel.sortedPositions[indexPath.row]
        
        let sellAction = UIContextualAction(style: .normal, title: "Sell") { [weak self] _, _, completion in
            let tradeVC = TradeViewController()
            tradeVC.presetSymbol = position.symbol
            tradeVC.presetSide = .sell
            tradeVC.presetQuantity = position.quantity
            self?.navigationController?.pushViewController(tradeVC, animated: true)
            completion(true)
        }
        sellAction.backgroundColor = .systemRed
        
        return UISwipeActionsConfiguration(actions: [sellAction])
    }
}

