        super.viewWillDisappear(animated)
        viewModel.stopQuoteRefresh()
    }
    
    private func applyPresets() {
        if let symbol = presetSymbol {
            symbolTextField.text = symbol
            viewModel.symbol = symbol
            Task {
                await viewModel.refreshQuote()
            }
        }
        if let side = presetSide {
            viewModel.selectedSide = side
            sideSegmentControl.selectedSegmentIndex = side == .buy ? 0 : 1
        }
        if let qty = presetQuantity {
            quantityTextField.text = String(format: "%.0f", qty)
            viewModel.quantity = String(format: "%.0f", qty)
        }
    }
    
    private func setupUI() {
        view.addSubview(scrollView)
        scrollView.addSubview(formStack)
        
        NSLayoutConstraint.activate([
            scrollView.topAnchor.constraint(equalTo: view.safeAreaLayoutGuide.topAnchor),
            scrollView.leadingAnchor.constraint(equalTo: view.leadingAnchor),
            scrollView.trailingAnchor.constraint(equalTo: view.trailingAnchor),
            scrollView.bottomAnchor.constraint(equalTo: view.bottomAnchor),
            
            formStack.topAnchor.constraint(equalTo: scrollView.contentLayoutGuide.topAnchor),
            formStack.leadingAnchor.constraint(equalTo: scrollView.contentLayoutGuide.leadingAnchor),
            formStack.trailingAnchor.constraint(equalTo: scrollView.contentLayoutGuide.trailingAnchor),
            formStack.bottomAnchor.constraint(equalTo: scrollView.contentLayoutGuide.bottomAnchor),
            formStack.widthAnchor.constraint(equalTo: scrollView.frameLayoutGuide.widthAnchor)
        ])
        
        // Symbol
        setupTextField(symbolTextField, placeholder: "Symbol (e.g., AAPL)", keyboardType: .default)
        symbolTextField.autocapitalizationType = .allCharacters
        symbolTextField.addTarget(self, action: #selector(symbolChanged), for: .editingChanged)
        formStack.addArrangedSubview(createFieldContainer(title: "Symbol", field: symbolTextField))
        
        // Search Results
        searchResultsTableView.translatesAutoresizingMaskIntoConstraints